def range_summary(nums):
    if not nums:
        return ''

    runs = []
    start, end = nums[0], nums[0]

    for num in nums:
        if num > end + 1:
            if start != end:
                runs.append(f'{start}-{end}')
            start = num
            end = num

    # handle the last run
    if start != end:
        runs.append(str(end))

    # join consecutive runs with commas and return result
    return ', '.join(sorted(runs))
